={{ (() => {
  const src = $('filter ready clips').item.json || {};
  const workflowRaw = $json.workflow;

  const clone = (v) => JSON.parse(JSON.stringify(v));
  const root = typeof workflowRaw === 'string' ? JSON.parse(workflowRaw) : clone(workflowRaw);
  const nodes = root && root.prompt && typeof root.prompt === 'object' ? root.prompt : root;

  const hasNode = (id) => nodes && nodes[String(id)] !== undefined;
  const actions = [];

  const patchNode = (id, mutator) => {
    const k = String(id);
    if (!hasNode(k)) return;
    const node = clone(nodes[k]);
    mutator(node);
    actions.push({
      type: 'addNode',
      id: k,
      overwrite: true,
      node
    });
  };

  const parseArr = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v === 'string') {
      try {
        const p = JSON.parse(v);
        return Array.isArray(p) ? p : [];
      } catch {
        return [];
      }
    }
    return [];
  };

  // ========= ВХОДНЫЕ ПЕРЕМЕННЫЕ =========
  const prompts = parseArr(src.chunksPositivePrompts);
  const frames = parseArr(src.chunksFramesCount);

  const startFrameFileName = src.startFrameFileName;
  const negativePrompt = src.negativePrompt ?? src.negativePrompts ?? '';

  const clipWidth = Number(src.clipWidth);
  const clipHeight = Number(src.clipHeight);
  const clipAspectRatioRaw = String(src.clipAspectRatio);

  const highNoiseSize = Number(src.highNoiseSize ?? Math.max(clipWidth, clipHeight));
  const finalSize = Number(src.finalSize ?? Math.max(clipWidth, clipHeight));

  // Сколько кадров добавлять к чанкам со 2-го и далее (для компенсации overlap)
  const OVERLAP_COMPENSATION_FRAMES = Number(src.overlapCompensationFrames ?? 6);
  // ======================================

  // target chunks: explicit > длины массивов
  const explicitCount = Number(src.chunksCount ?? src.targetChunks ?? src.totalChunks);
  let targetChunks = Number.isInteger(explicitCount) && explicitCount > 0
    ? explicitCount
    : Math.max(prompts.length, frames.length, 1);

  targetChunks = Math.max(1, Math.min(6, targetChunks));

  // ===== Детерминированные seed'ы в диапазоне 1..2147483647 =====
  const stable = (v) => {
    if (Array.isArray(v)) return v.map(stable);
    if (v && typeof v === 'object') {
      return Object.keys(v).sort().reduce((acc, k) => {
        acc[k] = stable(v[k]);
        return acc;
      }, {});
    }
    return v;
  };

  const seedPayload = {
    prompts,
    frames,
    startFrameFileName: startFrameFileName ?? '',
    negativePrompt: negativePrompt ?? '',
    clipWidth,
    clipHeight,
    clipAspectRatio: clipAspectRatioRaw,
    highNoiseSize,
    finalSize,
    targetChunks,
    overlapCompensationFrames: OVERLAP_COMPENSATION_FRAMES
  };

  const seedBase = JSON.stringify(stable(seedPayload));

  const SEED_MIN = 1;
  const SEED_MAX = 2147483647;
  const SEED_RANGE = SEED_MAX - SEED_MIN + 1;

  const toSeedRange = (n) => {
    if (!Number.isFinite(n)) return SEED_MIN;
    let x = Math.trunc(Math.abs(n));
    x = ((x - SEED_MIN) % SEED_RANGE + SEED_RANGE) % SEED_RANGE + SEED_MIN;
    if (x < SEED_MIN) return SEED_MIN;
    if (x > SEED_MAX) return SEED_MAX;
    return x;
  };

  const fnv1a = (str) => {
    let h = 0x811c9dc5;
    for (let i = 0; i < str.length; i++) {
      h ^= str.charCodeAt(i);
      h = Math.imul(h, 0x01000193);
    }
    return h >>> 0;
  };

  const makeSeed = (kind, chunkIndex) => {
    let h = fnv1a(`${kind}|${chunkIndex}|${seedBase}`);
    h ^= h >>> 16;
    h = Math.imul(h, 0x85ebca6b) >>> 0;
    h ^= h >>> 13;
    h = Math.imul(h, 0xc2b2ae35) >>> 0;
    h ^= h >>> 16;
    return toSeedRange(h);
  };

  // Удаляем лишние чанки > targetChunks
  for (let c = targetChunks + 1; c <= 6; c++) {
    const start = c * 100;
    const end = start + 99;
    for (let id = start; id <= end; id++) {
      if (hasNode(id)) {
        actions.push({ type: 'removeNode', nodeId: String(id) });
      }
    }
  }

  // Base patches
  if (startFrameFileName) {
    patchNode(6, (n) => { n.inputs.image = String(startFrameFileName); }); // Load Image
  }

  patchNode(31, (n) => { n.inputs.text = String(negativePrompt); }); // Negative_Prompt

  // Aspect ratio node
  const ratioKeys = ['1:1','4:3','3:2','5:4','16:9','16:10','21:9','2:1','1.85:1','2.39:1'];
  const clipAspectRatio = ratioKeys.includes(clipAspectRatioRaw) ? clipAspectRatioRaw : '16:9';

  patchNode(42, (n) => {
    if (Number.isFinite(clipWidth) && clipWidth > 0) n.inputs.width = Math.round(clipWidth);
    if (Number.isFinite(clipHeight) && clipHeight > 0) n.inputs.height = Math.round(clipHeight);
    for (const k of ratioKeys) n.inputs[k] = (k === clipAspectRatio);
  });

  if (Number.isFinite(highNoiseSize) && highNoiseSize > 0) {
    patchNode(43, (n) => { n.inputs.size = Math.round(highNoiseSize); }); // Set_High_Noise_Size
  }

  if (Number.isFinite(finalSize) && finalSize > 0) {
    patchNode(44, (n) => { n.inputs.size = Math.round(finalSize); }); // Set_Final_Size
  }

  // Chunk node id maps
  const promptId = (c) => (c === 1 ? 133 : c * 100 + 44); // 133,244,344...
  const framesId = (c) => (c === 1 ? 145 : c * 100 + 51); // 145,251,351...
  const finalId  = (c) => (c === 1 ? 139 : c * 100 + 39); // 139,239,339...

  // Noise node id maps
  const highNoiseId = (c) => (c === 1 ? 131 : c * 100 + 30); // 131,230,330...
  const lowNoiseId  = (c) => (c === 1 ? 135 : c * 100 + 33); // 135,233,333...

  // Patch prompts + frames (со 2-го чанка добавляем overlap compensation)
  for (let c = 1; c <= targetChunks; c++) {
    const p = prompts[c - 1];
    if (p !== undefined && p !== null && hasNode(promptId(c))) {
      patchNode(promptId(c), (n) => { n.inputs.value = String(p); });
    }

    const f = Number(frames[c - 1]);
    if (Number.isFinite(f) && f > 0 && hasNode(framesId(c))) {
      const extra = c === 1 ? 0 : Math.max(0, Math.round(OVERLAP_COMPENSATION_FRAMES));
      patchNode(framesId(c), (n) => { n.inputs.value = Math.round(f) + extra; });
    }
  }

  // save_output=true только у последнего чанка
  for (let c = 1; c <= targetChunks; c++) {
    if (hasNode(finalId(c))) {
      patchNode(finalId(c), (n) => { n.inputs.save_output = (c === targetChunks); });
    }
  }

  // Детерминированные seed для High/Low Noise по каждому чанку
  for (let c = 1; c <= targetChunks; c++) {
    const highSeed = makeSeed('HIGH', c);
    let lowSeed = makeSeed('LOW', c);
    if (lowSeed === highSeed) {
      lowSeed = (lowSeed === SEED_MAX) ? SEED_MIN : (lowSeed + 1);
    }

    if (hasNode(highNoiseId(c))) {
      patchNode(highNoiseId(c), (n) => { n.inputs.noise_seed = highSeed; });
    }
    if (hasNode(lowNoiseId(c))) {
      patchNode(lowNoiseId(c), (n) => { n.inputs.noise_seed = lowSeed; });
    }
  }

  return actions;
})() }}
